  1	import * as React from 'react';
  2	import {
  3	  Checkbox,
  4	  Dropdown,
  5	  DropdownList,
  6	  MenuToggle,
  7	  MenuToggleElement,
  8	  Radio,
  9	  Tooltip,
 10	  TooltipPosition
 11	} from '@patternfly/react-core';
 12	import { itemStyleWithoutInfo, menuStyle, titleStyle } from 'styles/DropdownStyles';
 13	import { HistoryManager, URLParam } from 'app/History';
 14	import { KialiIcon } from 'config/KialiIcon';
 15	import { TraceLimit } from 'components/Metrics/TraceLimit';
 16	import { infoStyle } from 'styles/IconStyle';
 17	import { serverConfig } from '../../config';
 18	
 19	export interface QuerySettings {
 20	  errorsOnly: boolean;
 21	  limit: number;
 22	  percentile?: string;
 23	}
 24	
 25	export interface DisplaySettings {
 26	  showSpansAverage: boolean;
 27	}
 28	
 29	export const percentilesOptions: DisplayOptionType[] = [
 30	  { id: 'all', labelText: 'All' },
 31	  { id: '0.75', labelText: 'p75' },
 32	  { id: '0.9', labelText: 'p90' },
 33	  { id: '0.99', labelText: 'p99' }
 34	];
 35	
 36	interface Props {
 37	  disabled: boolean;
 38	  onDisplaySettingsChanged: (settings: DisplaySettings) => void;
 39	  onQuerySettingsChanged: (settings: QuerySettings) => void;
 40	  percentilesPromise: Promise<Map<string, number>>;
 41	}
 42	
 43	type State = QuerySettings &
 44	  DisplaySettings & {
 45	    isOpen: boolean;
 46	  };
 47	
 48	interface DisplayOptionType {
 49	  id: string;
 50	  labelText: string;
 51	}
 52	
 53	export class TracesDisplayOptions extends React.Component<Props, State> {
 54	  private computedPercentiles: Map<string, number> | undefined;
 55	
 56	  constructor(props: Props) {
 57	    super(props);
 58	
 59	    const displaySettings = TracesDisplayOptions.retrieveDisplaySettings();
 60	    const querySettings = TracesDisplayOptions.retrieveQuerySettings();
 61	    this.state = { ...displaySettings, ...querySettings, isOpen: false };
 62	    props.percentilesPromise.then(p => (this.computedPercentiles = p));
 63	  }
 64	
 65	  public static retrieveDisplaySettings(): DisplaySettings {
 66	    const spansAverage =
 67	      HistoryManager.getParam(URLParam.TRACING_SHOW_SPANS_AVG) ||
 68	      sessionStorage.getItem(URLParam.TRACING_SHOW_SPANS_AVG) ||
 69	      'false';
 70	
 71	    return {
 72	      showSpansAverage: spansAverage === 'true'
 73	    };
 74	  }
 75	
 76	  public static retrieveQuerySettings(): QuerySettings {
 77	    const limit =
 78	      HistoryManager.getParam(URLParam.TRACING_LIMIT_TRACES) ||
 79	      sessionStorage.getItem(URLParam.TRACING_LIMIT_TRACES) ||
 80	      serverConfig.kialiFeatureFlags.uiDefaults.tracing.limit;
 81	
 82	    const errorsOnly =
 83	      HistoryManager.getParam(URLParam.TRACING_ERRORS_ONLY) ||
 84	      sessionStorage.getItem(URLParam.TRACING_ERRORS_ONLY) ||
 85	      'false';
 86	
 87	    const percentile =
 88	      HistoryManager.getParam(URLParam.TRACING_PERCENTILE) ||
 89	      sessionStorage.getItem(URLParam.TRACING_PERCENTILE) ||
 90	      undefined;
 91	
 92	    return {
 93	      errorsOnly: errorsOnly === 'true',
 94	      limit: Number(limit),
 95	      percentile: percentile
 96	    };
 97	  }
 98	
 99	  private onToggle = (isOpen): void => {
100	    this.setState({ isOpen: isOpen });
101	  };
102	
103	  render(): React.ReactNode {
104	    const { isOpen } = this.state;
105	
106	    return (
107	      <Dropdown
108	        toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
109	          <MenuToggle
110	            ref={toggleRef}
111	            id={'traces-display-settings'}
112	            data-test={'traces-display-settings'}
113	            onClick={() => this.onToggle(!isOpen)}
114	            isExpanded={isOpen}
115	          >
116	            Display
117	          </MenuToggle>
118	        )}
119	        isOpen={isOpen}
120	        onOpenChange={(isOpen: boolean) => this.onToggle(isOpen)}
121	      >
122	        <DropdownList>{this.getPopoverContent()}</DropdownList>
123	      </Dropdown>
124	    );
125	  }
126	
127	  private getPopoverContent(): React.ReactNode {
128	    return (
129	      <div id="traces-display-menu" className={menuStyle}>
130	        <div style={{ marginTop: '0.5rem' }}>
131	          <span className={titleStyle} style={{ paddingRight: 0 }}>
132	            Filter by percentile
133	          </span>
134	          <Tooltip
135	            key="tooltip_filter_by_percentile"
136	            position={TooltipPosition.right}
137	            content={
138	              <div style={{ textAlign: 'left' }}>
139	                <div>
140	                  These percentiles are computed from metrics. To refresh them, reload the page. The filter applies on
141	                  span durations. Thus, the filtered traces are the ones where at least one span for the service
142	                  satisfies the duration criteria.
143	                </div>
144	              </div>
145	            }
146	          >
147	            <KialiIcon.Info className={infoStyle} />
148	          </Tooltip>
149	        </div>
150	
151	        {percentilesOptions.map(item => {
152	          let label = item.labelText;
153	          if (this.computedPercentiles) {
154	            const val = this.computedPercentiles!.get(item.id);
155	            if (val) {
156	              label += ` (${val.toFixed(2)}ms+)`;
157	            }
158	          }
159	          return (
160	            <div key={item.id}>
161	              <label key={item.id} className={itemStyleWithoutInfo}>
162	                <Radio
163	                  id={item.id}
164	                  name={`percentiles${item.id}`}
165	                  isChecked={item.id === this.state.percentile || (item.id === 'all' && !this.state.percentile)}
166	                  label={label}
167	                  onChange={(_event, checked) => this.onPercentileChanged(item.id, checked)}
168	                  value={item.id}
169	                />
170	              </label>
171	            </div>
172	          );
173	        })}
174	
175	        <div className={titleStyle}>Errors</div>
176	        <div>
177	          <label className={itemStyleWithoutInfo}>
178	            <Checkbox
179	              id="errors-only"
180	              name="errors-only"
181	              isChecked={this.state.errorsOnly}
182	              label="Show only traces with errors"
183	              onChange={(_event, checked: boolean) => this.onErrorsOnlyChanged(checked)}
184	              value="errors-only"
185	            />
186	          </label>
187	        </div>
188	
189	        <TraceLimit
190	          asRadio={true}
191	          initialLimit={this.state.limit}
192	          onLimitChange={this.onLimitChanged}
193	          title="Trace limit"
194	          titleClassName={titleStyle}
195	        />
196	
197	        <div className={titleStyle}>Value axis</div>
198	        <div>
199	          <label className={itemStyleWithoutInfo}>
200	            <Radio
201	              id="yaxis-full"
202	              name="yaxis-full"
203	              isChecked={!this.state.showSpansAverage}
204	              label="Full trace duration"
205	              onChange={() => this.onValueAxisChanged(false)}
206	              value="yaxis-full"
207	            />
208	          </label>
209	        </div>
210	        <div>
211	          <label className={itemStyleWithoutInfo}>
212	            <Radio
213	              id="yaxis-avg"
214	              name="yaxis-avg"
215	              isChecked={this.state.showSpansAverage}
216	              label="Spans average duration"
217	              onChange={() => this.onValueAxisChanged(true)}
218	              value="yaxis-avg"
219	            />
220	          </label>
221	        </div>
222	      </div>
223	    );
224	  }
225	
226	  private onPercentileChanged = (id: string, checked: boolean): void => {
227	    if (checked) {
228	      this.saveValue(URLParam.TRACING_PERCENTILE, id);
229	      this.setState({ percentile: id }, () => this.props.onQuerySettingsChanged(this.state));
230	    }
231	  };
232	
233	  private onErrorsOnlyChanged = (checked: boolean): void => {
234	    this.saveValue(URLParam.TRACING_ERRORS_ONLY, String(checked));
235	    this.setState({ errorsOnly: checked }, () => this.props.onQuerySettingsChanged(this.state));
236	  };
237	
238	  private onLimitChanged = (limit: number): void => {
239	    this.saveValue(URLParam.TRACING_LIMIT_TRACES, String(limit));
240	    this.setState({ limit: limit }, () => this.props.onQuerySettingsChanged(this.state));
241	  };
242	
243	  private onValueAxisChanged = (showSpansAverage: boolean): void => {
244	    this.saveValue(URLParam.TRACING_SHOW_SPANS_AVG, String(showSpansAverage));
245	    this.setState({ showSpansAverage: showSpansAverage }, () => this.props.onDisplaySettingsChanged(this.state));
246	  };
247	
248	  private saveValue = (key: URLParam, value: string): void => {
249	    sessionStorage.setItem(key, value);
250	    HistoryManager.setParam(key, value);
251	  };
252	}

